ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
  isSuccess: payload.successful,
  apiName: Mule::p('api.name'),
  apiVersion: Mule::p('api.version'),
  traceId: correlationId,
  timestamp: now() as DateTime,
  message: "Failed",
  sfResponse: write({
    "items":
    payload.items map ((item) -> 
    item.exception - "stackTrace")
},"application/json")
} as Object {encoding: "UTF-8", mediaType: "application/json"}
